css:
.loader {color: var(--loader-color, #db2777);
  --loader-secondary-color: #f9a8d4;
  --loader-bg: #ffffff;
   width: 50px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px currentColor inset;
   border-radius: 50%;
   position: relative;
}
.loader:before, .loader:after  {
  content: "";
   position: absolute;
   top: 5px;
   left: calc(50% - 12.5px);
   box-shadow: inherit;
   width: 25px;
   aspect-ratio: 1;
   border-radius: 50%;
   transform-origin: 50% calc(100% - 5px);
   animation: l7 1.5s linear infinite;
}
.loader:after  {
  top: calc(100% + 2px);
   transform-origin: 50% -27px;
   animation-delay: -0.75s;
}
@keyframes l7  {
  to  {
  transform: rotate(360deg);
}
}
